const checkpoints = [];

// Load instrumentation and data
let filterParams = null;
try {
  filterParams = JSON.parse(localStorage.getItem('task1_chairFilterParams') || 'null');
} catch (e) {
  filterParams = null;
}
const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// CP1 (0.4): User used correct filters/sort for ergonomic office chairs under $250 with rating >= 4
let usedCorrectFilters = false;
if (filterParams && typeof filterParams === 'object') {
  const filters = filterParams.filters || {};
  const sortBy = filterParams.sort_by;
  const categoryCode = filterParams.category_code;

  const categoryOk = categoryCode === 'office_chairs';
  const maxPriceOk = filters.max_price != null && filters.max_price <= 250;
  const minRatingOk = filters.min_rating != null && filters.min_rating >= 4.0;
  const ergonomicFilterOk = (filters.chair_type === 'ergonomic') || (filters.is_ergonomic === true);
  const sortOk = sortBy === 'rating_high_to_low';

  usedCorrectFilters = categoryOk && maxPriceOk && minRatingOk && ergonomicFilterOk && sortOk;
}
checkpoints.push({ passed: usedCorrectFilters, weight: 0.4 });

// Identify qualifying chairs in catalog: ergonomic, office_chairs, under $250, rating>=4, available in Black
const qualifyingChairs = products.filter(p =>
  p &&
  p.status === 'active' &&
  p.category_code === 'office_chairs' &&
  typeof p.base_price === 'number' && p.base_price <= 250 &&
  (p.chair_type === 'ergonomic' || p.is_ergonomic === true) &&
  typeof p.rating_average === 'number' && p.rating_average >= 4.0 &&
  Array.isArray(p.color_options) && p.color_options.includes('Black')
);

let addedBestChairCorrectly = false;
if (qualifyingChairs.length > 0) {
  const highestRating = Math.max.apply(null, qualifyingChairs.map(p => p.rating_average || 0));
  const bestChairs = qualifyingChairs.filter(p => (p.rating_average || 0) === highestRating);
  const bestChairIds = bestChairs.map(p => p.id);

  const activeCart = carts.find(c => c && c.is_active);
  if (activeCart) {
    const itemsInCart = cartItems.filter(ci => ci && ci.cart_id === activeCart.id);
    const matchingItems = itemsInCart.filter(ci =>
      bestChairIds.includes(ci.product_id) &&
      ci.quantity === 1 &&
      ci.selected_color === 'Black'
    );
    addedBestChairCorrectly = matchingItems.length > 0;
  }
}

// CP2 (0.6): Active cart contains at least one best qualifying chair in Black with quantity 1
checkpoints.push({ passed: addedBestChairCorrectly, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load instrumentation and data
let searchParams = null;
try {
  searchParams = JSON.parse(localStorage.getItem('task2_searchParams') || 'null');
} catch (e) {
  searchParams = null;
}
const products = JSON.parse(localStorage.getItem('products') || '[]');
const quoteRequests = JSON.parse(localStorage.getItem('quote_requests') || '[]');

// CP1 (0.4): User searched with correct filters/sort for qualifying printers
let usedCorrectSearchFilters = false;
if (searchParams && typeof searchParams === 'object') {
  const filters = searchParams.filters || {};
  const sortBy = searchParams.sort_by;

  const productTypeOk = filters.product_type === 'printer';
  const techOk = filters.printer_technology === 'laser';
  const colorOk = filters.is_color_printing === true;
  const duplexOk = filters.has_duplex_printing === true;
  const wifiOk = filters.has_wifi_connectivity === true;
  const maxPriceOk = filters.max_price != null && filters.max_price <= 400;
  const sortOk = sortBy === 'price_low_to_high';

  usedCorrectSearchFilters = productTypeOk && techOk && colorOk && duplexOk && wifiOk && maxPriceOk && sortOk;
}
checkpoints.push({ passed: usedCorrectSearchFilters, weight: 0.4 });

// Find all qualifying printers in catalog
const qualifyingPrinters = products.filter(p =>
  p &&
  p.product_type === 'printer' &&
  p.printer_technology === 'laser' &&
  !!p.is_color_printing &&
  !!p.has_duplex_printing &&
  !!p.has_wifi_connectivity &&
  typeof p.base_price === 'number' && p.base_price <= 400
);

let quotedCheapestCorrectly = false;
if (qualifyingPrinters.length > 0) {
  const cheapestPrice = Math.min.apply(null, qualifyingPrinters.map(p => p.base_price || 0));
  const cheapestPrinters = qualifyingPrinters.filter(p => (p.base_price || 0) === cheapestPrice);
  const cheapestIds = cheapestPrinters.map(p => p.id);

  const matchingQuotes = quoteRequests.filter(qr =>
    qr &&
    cheapestIds.includes(qr.product_id) &&
    qr.status === 'submitted' &&
    qr.quantity === 3
  );
  quotedCheapestCorrectly = matchingQuotes.length > 0;
}

// CP2 (0.6): At least one submitted quote request exists for the cheapest qualifying printer with quantity 3
checkpoints.push({ passed: quotedCheapestCorrectly, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load instrumentation and data
let filterParams = null;
try {
  filterParams = JSON.parse(localStorage.getItem('task3_paperFilterParams') || 'null');
} catch (e) {
  filterParams = null;
}
const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// CP1 (0.3): User used correct filters/sort for A4 paper between $5 and $20
let usedCorrectFilters = false;
if (filterParams && typeof filterParams === 'object') {
  const categoryCode = filterParams.category_code;
  const filters = filterParams.filters || {};
  const sortBy = filterParams.sort_by;

  const categoryOk = categoryCode === 'paper_media';
  const paperSizeOk = (filters.paper_size || filters.paperSize) === 'a4' || (filters.paper_size || filters.paperSize) === 'A4';
  const minPriceOk = filters.min_price != null ? (filters.min_price >= 5) : true;
  const maxPriceOk = filters.max_price != null && filters.max_price <= 20;
  const sortOk = sortBy === 'price_low_to_high';

  usedCorrectFilters = categoryOk && paperSizeOk && maxPriceOk && minPriceOk && sortOk;
}
checkpoints.push({ passed: usedCorrectFilters, weight: 0.3 });

// Identify qualifying A4 paper products in catalog
const qualifyingPapers = products.filter(p =>
  p &&
  p.category_code === 'paper_media' &&
  p.product_type === 'paper' &&
  p.paper_size === 'a4' &&
  typeof p.base_price === 'number' && p.base_price >= 5 && p.base_price <= 20
);
const qualifyingPaperIds = qualifyingPapers.map(p => p.id);

// Check cart contents
let hasThreeDistinctPapersWithQty4 = false;
if (qualifyingPaperIds.length > 0) {
  const activeCart = carts.find(c => c && c.is_active);
  if (activeCart) {
    const itemsInCart = cartItems.filter(ci => ci && ci.cart_id === activeCart.id);
    const a4PaperLines = itemsInCart.filter(ci => qualifyingPaperIds.includes(ci.product_id));

    // Distinct qualifying paper products where quantity is exactly 4 on at least one line
    const productIdToQty = {};
    a4PaperLines.forEach(ci => {
      if (!productIdToQty[ci.product_id]) {
        productIdToQty[ci.product_id] = 0;
      }
      productIdToQty[ci.product_id] += ci.quantity || 0;
    });

    const distinctA4ProductIds = Object.keys(productIdToQty);
    const productsWithAtLeast4 = distinctA4ProductIds.filter(pid => productIdToQty[pid] >= 4);

    // Exactly 3 different A4 paper products in cart, each with total quantity >= 4
    hasThreeDistinctPapersWithQty4 = (distinctA4ProductIds.length === 3) && (productsWithAtLeast4.length === 3);
  }
}

// CP2 (0.7): Active cart has exactly three distinct qualifying A4 papers, each with total quantity >= 4
checkpoints.push({ passed: hasThreeDistinctPapersWithQty4, weight: 0.7 });

return checkPointsTotal = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load instrumentation and data
let searchParams = null;
try {
  searchParams = JSON.parse(localStorage.getItem('task4_searchFilterParams') || 'null');
} catch (e) {
  searchParams = null;
}
const products = JSON.parse(localStorage.getItem('products') || '[]');
const savedItems = JSON.parse(localStorage.getItem('saved_items') || '[]');

// CP1 (0.4): User searched with correct filters for docking stations compatible with ProBook 450
let usedCorrectSearchFilters = false;
if (searchParams && typeof searchParams === 'object') {
  const filters = searchParams.filters || {};
  const productTypeOk = filters.product_type === 'docking_station';
  const compatibleOk = filters.compatible_with_model === 'ProBook 450';
  usedCorrectSearchFilters = productTypeOk && compatibleOk;
}
checkpoints.push({ passed: usedCorrectSearchFilters, weight: 0.4 });

// Find qualifying docking stations in catalog
const qualifyingDocks = products.filter(p =>
  p &&
  p.product_type === 'docking_station' &&
  p.category_code === 'electronics' &&
  Array.isArray(p.compatible_models) && p.compatible_models.includes('ProBook 450') &&
  Array.isArray(p.color_options) && p.color_options.includes('Black')
);
const qualifyingDockIds = qualifyingDocks.map(p => p.id);

// Check saved items for a matching docking station saved in black
let savedQualifyingDock = false;
if (qualifyingDockIds.length > 0 && Array.isArray(savedItems)) {
  savedQualifyingDock = savedItems.some(si => {
    if (!si) return false;
    if (!qualifyingDockIds.includes(si.product_id)) return false;
    const product = qualifyingDocks.find(p => p.id === si.product_id);
    const selectedColor = si.selected_color || (product && product.default_color) || null;
    return selectedColor === 'Black';
  });
}

// CP2 (0.6): At least one qualifying black docking station compatible with ProBook 450 is in saved_items
checkpoints.push({ passed: savedQualifyingDock, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load instrumentation and data
let filterParams = null;
try {
  filterParams = JSON.parse(localStorage.getItem('task5_monitorFilterParams') || 'null');
} catch (e) {
  filterParams = null;
}
const products = JSON.parse(localStorage.getItem('products') || '[]');
const comparisons = JSON.parse(localStorage.getItem('product_comparisons') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// CP1 (0.3): User filtered for 27-inch monitors under $350
let usedCorrectMonitorFilters = false;
if (filterParams && typeof filterParams === 'object') {
  const categoryCode = filterParams.category_code;
  const filters = filterParams.filters || {};

  const categoryOk = categoryCode === 'monitors';
  const sizeOk = filters.screen_size_inches === 27;
  const maxPriceOk = filters.max_price != null && filters.max_price <= 350;

  usedCorrectMonitorFilters = categoryOk && sizeOk && maxPriceOk;
}
checkpoints.push({ passed: usedCorrectMonitorFilters, weight: 0.3 });

// Determine monitors in active comparison and identify highest resolution
const activeComparison = comparisons.find(c => c && c.is_active);
let comparedTwoQualifyingMonitors = false;
let highestResMonitorIds = [];

if (activeComparison && Array.isArray(activeComparison.product_ids)) {
  const comparedProducts = products.filter(p => activeComparison.product_ids.includes(p.id));
  const qualifyingCompared = comparedProducts.filter(p =>
    p &&
    p.category_code === 'monitors' &&
    typeof p.screen_size_inches === 'number' && p.screen_size_inches === 27 &&
    typeof p.base_price === 'number' && p.base_price <= 350 &&
    (p.is_comparable !== false)
  );

  comparedTwoQualifyingMonitors = qualifyingCompared.length >= 2;

  if (qualifyingCompared.length > 0) {
    let maxPixels = -1;
    qualifyingCompared.forEach(p => {
      const width = p.resolution_width || 0;
      const height = p.resolution_height || 0;
      const pixels = width * height;
      if (pixels > maxPixels) {
        maxPixels = pixels;
      }
    });
    highestResMonitorIds = qualifyingCompared
      .filter(p => (p.resolution_width || 0) * (p.resolution_height || 0) === maxPixels)
      .map(p => p.id);
  }
}

// CP2 (0.3): Active comparison contains at least two qualifying 27" monitors under $350
checkpoints.push({ passed: comparedTwoQualifyingMonitors, weight: 0.3 });

// CP3 (0.4): Cart contains 2 units of a highest-resolution compared monitor with standard shipping
let addedHighestResMonitorCorrectly = false;
if (highestResMonitorIds.length > 0) {
  const activeCart = carts.find(c => c && c.is_active);
  if (activeCart) {
    const itemsInCart = cartItems.filter(ci => ci && ci.cart_id === activeCart.id);
    const matchingItems = itemsInCart.filter(ci =>
      highestResMonitorIds.includes(ci.product_id) &&
      ci.quantity === 2 &&
      ci.shipping_method_code === 'standard_shipping_3_5_business_days'
    );
    addedHighestResMonitorCorrectly = matchingItems.length > 0;
  }
}
checkpoints.push({ passed: addedHighestResMonitorCorrectly, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load instrumentation and data
let filterParams = null;
try {
  filterParams = JSON.parse(localStorage.getItem('task6_cleaningFilterParams') || 'null');
} catch (e) {
  filterParams = null;
}
const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// CP1 (0.4): User used correct filters/sort for eco-certified cleaning products with free shipping and rating >= 4
let usedCorrectFilters = false;
if (filterParams && typeof filterParams === 'object') {
  const categoryCode = filterParams.category_code;
  const filters = filterParams.filters || {};
  const sortBy = filterParams.sort_by;

  const categoryOk = categoryCode === 'cleaning_supplies';
  const ecoOk = filters.is_eco_certified === true;
  const freeShipOk = filters.has_free_shipping === true;
  const minRatingOk = filters.min_rating != null && filters.min_rating >= 4.0;
  const sortOk = sortBy === 'rating_high_to_low';

  usedCorrectFilters = categoryOk && ecoOk && freeShipOk && minRatingOk && sortOk;
}
checkpoints.push({ passed: usedCorrectFilters, weight: 0.4 });

// Qualifying cleaning products in catalog
const qualifyingProducts = products.filter(p =>
  p &&
  p.category_code === 'cleaning_supplies' &&
  p.product_type === 'cleaning_product' &&
  !!p.is_eco_certified &&
  !!p.has_free_shipping &&
  typeof p.rating_average === 'number' && p.rating_average >= 4.0
);
const qualifyingIds = qualifyingProducts.map(p => p.id);

// Check cart for two different qualifying products with quantities 3 and 2 based on add order
let hasTwoDifferentWithQuantities = false;
if (qualifyingIds.length > 0) {
  const activeCart = carts.find(c => c && c.is_active);
  if (activeCart) {
    const itemsInCart = cartItems.filter(ci => ci && ci.cart_id === activeCart.id && qualifyingIds.includes(ci.product_id));

    if (itemsInCart.length > 0) {
      // Sort by created_at to determine first and second products added
      const sorted = itemsInCart.slice().sort((a, b) => {
        const da = a.created_at ? new Date(a.created_at).getTime() : 0;
        const db = b.created_at ? new Date(b.created_at).getTime() : 0;
        return da - db;
      });

      const orderedProductIds = [];
      sorted.forEach(ci => {
        if (!orderedProductIds.includes(ci.product_id)) {
          orderedProductIds.push(ci.product_id);
        }
      });

      if (orderedProductIds.length >= 2) {
        const firstId = orderedProductIds[0];
        const secondId = orderedProductIds[1];

        let qtyFirst = 0;
        let qtySecond = 0;
        sorted.forEach(ci => {
          if (ci.product_id === firstId) qtyFirst += ci.quantity || 0;
          if (ci.product_id === secondId) qtySecond += ci.quantity || 0;
        });

        hasTwoDifferentWithQuantities = qtyFirst >= 3 && qtySecond >= 2;
      }
    }
  }
}

// CP2 (0.6): Two different qualifying eco cleaning products in cart with first having >=3 units and second >=2 units
checkpoints.push({ passed: hasTwoDifferentWithQuantities, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load instrumentation and data
let quickOrderUsed = false;
let orderSummaryViewed = false;
try {
  const rawQuick = localStorage.getItem('task7_quickOrderUsed');
  quickOrderUsed = rawQuick != null ? JSON.parse(rawQuick) : false;
} catch (e) {
  quickOrderUsed = false;
}
try {
  const rawSummary = localStorage.getItem('task7_orderSummaryViewed');
  orderSummaryViewed = rawSummary != null ? JSON.parse(rawSummary) : false;
} catch (e) {
  orderSummaryViewed = false;
}

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const checkoutSessions = JSON.parse(localStorage.getItem('checkout_sessions') || '[]');

// Identify qualifying gigabit 24-port network switches dynamically
const qualifyingSwitches = products.filter(p => {
  if (!p) return false;
  if (p.product_type !== 'network_switch' || p.category_code !== 'electronics') return false;
  const name = (p.name || '').toLowerCase();
  return name.includes('gigabit') && name.includes('24') && name.includes('switch');
});
const qualifyingSwitchIds = qualifyingSwitches.map(p => p.id);

// CP1 (0.6): Quick order used AND cart contains at least 50 units of a qualifying switch
let quickOrderAndCartOk = false;
if (quickOrderUsed && qualifyingSwitchIds.length > 0) {
  const activeCart = carts.find(c => c && c.is_active);
  if (activeCart) {
    const itemsInCart = cartItems.filter(ci => ci && ci.cart_id === activeCart.id && qualifyingSwitchIds.includes(ci.product_id));
    const totalQty = itemsInCart.reduce((sum, ci) => sum + (ci.quantity || 0), 0);
    quickOrderAndCartOk = totalQty >= 50;
  }
}
checkpoints.push({ passed: quickOrderAndCartOk, weight: 0.6 });

// CP2 (0.4): Order summary viewed AND active checkout session uses invoice payment
let orderSummaryAndInvoiceOk = false;
if (orderSummaryViewed) {
  const activeSession = checkoutSessions.find(s => s && s.is_active);
  if (activeSession && activeSession.payment_method === 'business_invoice') {
    orderSummaryAndInvoiceOk = true;
  }
}
checkpoints.push({ passed: orderSummaryAndInvoiceOk, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const demoRequests = JSON.parse(localStorage.getItem('demo_requests') || '[]');

// Identify analytics software products (enterprise analytics software solutions)
const analyticsProducts = products.filter(p =>
  p &&
  p.category_code === 'analytics' &&
  p.product_type === 'software'
);
const analyticsIds = analyticsProducts.map(p => p.id);

// Filter demo requests that target an analytics software product at 10:00 AM in April 2026 on a weekday
const matchingDateTimeRequests = demoRequests.filter(dr => {
  if (!dr) return false;
  if (!analyticsIds.includes(dr.product_id)) return false;
  if (dr.preferred_time_slot !== '10_00_am') return false;

  let d;
  try {
    d = new Date(dr.preferred_date);
  } catch (e) {
    d = null;
  }
  if (!d || isNaN(d.getTime())) return false;

  const year = d.getUTCFullYear();
  const month = d.getUTCMonth(); // 0-based: 3 = April
  const dayOfWeek = d.getUTCDay(); // 0=Sun, 1=Mon, ..., 5=Fri
  const isWeekday = dayOfWeek >= 1 && dayOfWeek <= 5;

  return year === 2026 && month === 3 && isWeekday;
});

// CP1 (0.5): At least one demo request meets product + date (April 2026 weekday) + 10:00 AM time slot
const anyCorrectDateTime = matchingDateTimeRequests.length > 0;
checkpoints.push({ passed: anyCorrectDateTime, weight: 0.5 });

// CP2 (0.5): At least one such request also has exactly 5 attendees
const withCorrectAttendees = matchingDateTimeRequests.filter(dr => dr.number_of_attendees === 5);
checkpoints.push({ passed: withCorrectAttendees.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
